from functools import singledispatch
@singledispatch
def func(arg):
    print(f"Default: {arg}")
@func.register(int)
def _(arg):
    print(f"Integer: {arg}")
@func.register(str)
def _(arg):
    print(f"String: {arg}")
func(1)        # Output: Integer: 1
func('hello')  # Output: String: hello

